$ErrorActionPreference = "Stop"

$project = "C:\Users\arauj\grafica-flash"

if (!(Test-Path -LiteralPath $project)) {
  Write-Host "Projeto nao encontrado em $project" -ForegroundColor Red
  exit 1
}

Set-Location $project

$utf8NoBom = New-Object System.Text.UTF8Encoding($false)

function Write-Base64File($relativePath, $base64Content) {
  $target = Join-Path $project $relativePath
  $directory = Split-Path $target -Parent
  New-Item -ItemType Directory -Force $directory | Out-Null
  $bytes = [System.Convert]::FromBase64String($base64Content.Trim())
  $content = [System.Text.Encoding]::UTF8.GetString($bytes)
  [System.IO.File]::WriteAllText($target, $content, $utf8NoBom)
}

Write-Base64File "lib\admin-auth.ts" @"

"@

Write-Base64File "app\admin\page.tsx" @"

"@

Write-Base64File "app\api\admin\dashboard\route.ts" @"

"@

Write-Base64File "app\api\admin\action\route.ts" @"

"@

Write-Base64File "app\api\admin\team\route.ts" @"

"@

Write-Base64File "app\api\admin\scan\route.ts" @"

"@

# Configura Cron 24h sem destruir outras chaves do vercel.json.
$vercelPath = Join-Path $project "vercel.json"
$cronEntry = [ordered]@{ path = "/api/admin/scan"; schedule = "0 9 * * *" }

if (Test-Path -LiteralPath $vercelPath) {
  try {
    $json = Get-Content -LiteralPath $vercelPath -Raw | ConvertFrom-Json
  } catch {
    $json = [PSCustomObject]@{}
  }
} else {
  $json = [PSCustomObject]@{}
}

$props = $json.PSObject.Properties.Name

if ($props -notcontains "crons") {
  $json | Add-Member -NotePropertyName "crons" -NotePropertyValue @()
}

$existing = @($json.crons) | Where-Object { $_.path -ne "/api/admin/scan" }
$json.crons = @($existing + ([PSCustomObject]$cronEntry))

$json | ConvertTo-Json -Depth 20 | Set-Content -LiteralPath $vercelPath -Encoding UTF8

Remove-Item -Recurse -Force ".next" -ErrorAction SilentlyContinue

Write-Host "Admin Master Plus instalado." -ForegroundColor Green
Write-Host "Cron 24h configurado em vercel.json para /api/admin/scan." -ForegroundColor Cyan
Write-Host "Agora rode: npm run build" -ForegroundColor Yellow
